// Get the optimized prompt from the previous node
const prompt = $input.first().json.veo_prompt || $input.first().json.prompt;

// Validate
if (!prompt || typeof prompt !== 'string' || prompt.length < 10) {
  throw new Error('Valid prompt required (min 10 characters)');
}

// Strip any audio-related language that might trigger RAI filters
// (optional defensive cleanup - comment out if your upstream prompt is already clean)
const cleanPrompt = prompt
  .replace(/\b(music|soundtrack|audio|voiceover|dialogue|speaking|singing|song|sfx|sound effect)s?\b/gi, '')
  .replace(/\s+/g, ' ')
  .trim();

return {
  json: {
    veo_request_body: {
      prompt: cleanPrompt,
      duration: 8,
      aspect_ratio: "9:16"
    }
  }
};

const part = $input.first().json.candidates[0].content.parts
  .find(p => p.inlineData || p.inline_data);

const inline = part.inlineData || part.inline_data;

return {
  json: {
    mimeType: inline.mimeType || inline.mime_type
  },
  binary: {
    data: {
      data: inline.data,
      mimeType: inline.mimeType || inline.mime_type || "image/png",
      fileName: "nanobanana-output.png"
    }
  }
};

